import re
import json
from PhseXlib.locals import CONFIG
from PhseXlib.op_lib import op_stop_os
from phsex import symbol_table
from pathlib import Path
from sys import exit

# CONFIG = json.load(Path("build.json").open("r",encoding="utf-8"))
string = re.compile(r'"([^"\\]|\\.)*"')
number =  re.compile(r'[0-9]\d*')
flag = re.compile(r'^f:.*')
point = re.compile(r"^\[(?![0-9]+$)[a-zA-Z0-9_]+\]$")
flag = re.compile(r"TAG\:")

def addres_transformer(addres):
    REG_ADDR = re.compile(r"R[0-9]")
    RAM_ADDR = re.compile(r'0x[0-9a-fA-F]+')
    ADDR_ROUTE = {"file":"", "key":""}

    if re.fullmatch(REG_ADDR,addres):   # 寄存器地址
        ADDR_ROUTE["file"] = CONFIG["REG_file"] # type: ignore
        ADDR_ROUTE["key"] = addres
    elif re.fullmatch(RAM_ADDR,addres): # 内存地址
        ADDR_ROUTE["file"] = CONFIG["RAM_file"] # type: ignore
        ADDR_ROUTE["key"] = addres
    elif re.fullmatch(string,addres):   # 字符串 
        ADDR_ROUTE["file"] = "TYPE:STRING"
        ADDR_ROUTE["key"] = addres[1:-1]
    elif re.fullmatch(number,addres):   # 整数
        ADDR_ROUTE["file"] = "TYPE:INT"
        ADDR_ROUTE["key"] = addres

    elif re.fullmatch(point,addres):    # 指针
        ADDR_ROUTE["file"] = "TYPE:POINT"
        if addres[1:-1] in symbol_table:
            ADDR_ROUTE["key"] = addres[1:-1] # 记录指针名
        else:
            print(f"Point {addres[1:-1]} not found in symbol table.")
            exit()
    
    elif re.match(point, addres):       # 标签
        ADDR_ROUTE["file"] = "TYPE:FLAG"
        flag_dict = json.load(Path(CONFIG["REG_flag_file"]).open("r",encoding="utf-8"))
        if addres[4:] in flag_dict:
            ADDR_ROUTE["key"] = addres[4:]
        else:
            print(f"Flag {addres[4:]} not found in flag register.")
            exit()
    else:
        print(f"Arguments {addres} Error.")
        exit()
    return ADDR_ROUTE